import { cookies } from "next/headers"
import { redirect } from "next/navigation"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { ADMIN_SESSION_COOKIE, buildAdminApiUrl, parseAdminSession } from "@/lib/admin-auth"

interface AdminProfile {
  username: string
  roles: string[]
}

const ADMIN_ME_ENDPOINT = "/api/v1/admin/me"

const getAdminProfile = async (authHeader: string): Promise<AdminProfile | null> => {
  try {
    const response = await fetch(buildAdminApiUrl(ADMIN_ME_ENDPOINT), {
      method: "GET",
      headers: {
        Accept: "application/json",
        Authorization: authHeader,
      },
      cache: "no-store",
    })

    if (!response.ok) {
      return null
    }

    const payload = (await response.json()) as { username?: unknown; roles?: unknown }
    const username =
      typeof payload.username === "string" && payload.username.trim().length > 0 ? payload.username : "administrator"
    const roles = Array.isArray(payload.roles)
      ? payload.roles.filter((role): role is string => typeof role === "string")
      : []

    return {
      username,
      roles,
    }
  } catch {
    return null
  }
}

export default async function AdminDashboardPage() {
  const cookieStore = await cookies()
  const sessionValue = cookieStore.get(ADMIN_SESSION_COOKIE)?.value
  const session = parseAdminSession(sessionValue)

  if (!session) {
    redirect("/admin/login")
  }

  const adminProfile = await getAdminProfile(session.authHeader)

  if (!adminProfile) {
    redirect("/admin/login")
  }

  return (
    <div className="min-h-screen bg-background flex items-center justify-center p-4">
      <Card className="w-full max-w-2xl border-maroon/20">
        <CardHeader className="flex flex-row items-start justify-between gap-4">
          <div className="space-y-1">
            <CardTitle>Admin Dashboard</CardTitle>
            <CardDescription>Signed in as {adminProfile.username}.</CardDescription>
          </div>

          <form action="/admin/logout" method="post">
            <Button type="submit" variant="outline">
              Log out
            </Button>
          </form>
        </CardHeader>

        <CardContent className="space-y-2 text-sm text-muted-foreground">
          <p>Use this page as the starting point for admin-only tools and reports.</p>
          <p>
            Roles: {adminProfile.roles.length > 0 ? adminProfile.roles.join(", ") : "No roles returned by the backend."}
          </p>
        </CardContent>
      </Card>
    </div>
  )
}
